use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
enum HttpMethod {
    Get,
    Post,
}

struct RequestContext {
    user_id: u64,
    current_state: String,
    data: HashMap<String, String>,
}

impl RequestContext {
    fn new(user_id: u64) -> Self {
        RequestContext {
            user_id,
            current_state: "initial".to_string(),
            data: HashMap::new(),
        }
    }

    fn process_step(&mut self, next_input: &str) -> Result<String, String> {
        match (self.current_state.as_str(), next_input) {
            ("initial", "user_data") => {
                if let Some(value) = next_input.strip_prefix(":") { 
                    self.data.insert("bio".to_string(), value.to_string());
                    Ok("StateUpdated: Profile Bio Captured".to_string())
                } else {
                    Err("Input did not start with ':' in initial state".to_string())
                }
            }
            ("profile_captured", "auth_token") => {
                if next_input.contains(":VALID:") { 
                    self.current_state = "authenticated".to_string();
                    Ok("StateUpdated: User Authenticated Successfully".to_string())
                } else {
                    Err("Invalid token provided for authentication step".to_string())
                }
            }
            (s, _) => Err(format!("Cannot transition from state '{}' with input '{}'.", s, next_input)),
        }
    }
}

use std::fmt::{self, Display};
use std::thread;
use std::time::Duration;

#[derive(Debug, Clone, Copy, PartialEq)]
enum NetworkState {
    Disconnected,
    Connecting,
    Connected,
    Failed,
}

impl Display for NetworkState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            NetworkState::Disconnected => write!(f, "Disconnected"),
            NetworkState::Connecting => write!(f, "Connecting"),
            NetworkState::Connected => write!(f, "Connected"),
            NetworkState::Failed => write!(f, "Failed"),
        }
    }
}

struct ConnectionManager {
    state: NetworkState,
}

impl ConnectionManager {
    fn new() -> Self {
        ConnectionManager { state: NetworkState::Disconnected }
    }

    fn transition(&mut self, next_state: NetworkState) -> Result<(), String> {
        let current = self.state;
        match (current, next_state) {
            (NetworkState::Disconnected, NetworkState::Connecting) => {
                self.state = next_state; 
                Ok(())
            }
            (NetworkState::Connecting, NetworkState::Connected) => {
                self.state = next_state;
                Ok(())
            }
            (NetworkState::Connecting, NetworkState::Failed) => {
                self.state = next_state;
                Ok(())
            }
            (NetworkState::Connected, NetworkState::Disconnected) => {
                self.state = next_state;
                Ok(())
            }
            (_, _) => Err(format!("Invalid transition from {} to {}", current, next_state)),
        }
    }
}

fn main() {
    let mut manager = ConnectionManager::new();
    println!("Initial State: {}", manager.state);

    if let Err(e) = manager.transition(NetworkState::Connecting) {
        println!("Error: {}", e);
    }
    println!("Current State after connect attempt: {}", manager.state);

    thread::sleep(Duration::from_millis(100));

    if let Ok(()) = manager.transition(NetworkState::Connected) {
        println!("Successfully connected! Current State: {}", manager.state);
    }

    thread::sleep(Duration::from_millis(100));

    match manager.transition(NetworkState::Disconnected) {
        Ok(_) => println!("Manually disconnected. Final State: {}", manager.state),
        Err(e) => println!("Failed to change state: {}", e),
    }
}

use std::fmt;

#[derive(Debug)]
enum GameState {
    Uninitialized,
    ReadyToMove,
    Moving(String),
    PerformingAction(String),
}

impl fmt::Display for GameState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            GameState::Uninitialized => write!(f, "Never Started"),
            GameState::ReadyToMove => write!(f, "Waiting for Input"),
            GameState::Moving(dir) => write!(f, "Currently Moving towards {}", dir),
            GameState::PerformingAction(action) => write!(f, "Busy with Action: {}", action),
        }
    }
}

fn process_state_transition(current_state: GameState, input_event: &str) -> GameState {
    match (&current_state, input_event) {
        ((GameState::Uninitialized, "Start_")) => GameState::ReadyToMove,
        ((GameState::ReadyToMove, "Move North")) => GameState::Moving(String::from("North")),
        ((GameState::Moving(_), "Stop")) => GameState::ReadyToMove,
        ((GameState::PerformingAction(_), "Input Received")) => GameState::PerformingAction(String::from("Cooldown")),
        ((GameState::PerformingAction(_), "Finished")) => GameState::ReadyToMove,
        _ => current_state,
    }
}

fn main() {
    let mut state = GameState::Uninitialized;
    println!("Initial State: {}", state);

    state = process_state_transition(state, "Start_");
    println!("After Start Input: {}", state);

    state = process_state_transition(state, "Move North");
    println!("After Move Input: {}", state);

    state = process_state_transition(state, "Stop");
    println!("After Stop Input: {}", state);

    state = process_state_transition(state, "Move North");
    println!("Attempted Move from Ready: {}", state);
}

use std::fmt::{self, Display};
use std::io;

#[derive(Debug, PartialEq)]
enum JobState {
    Pending,
    Processing(String),
    Completed(u64),
    Failed(String),
}

impl Display for JobState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            JobState::Pending => write!(f, "PENDING_STATUS"),
            JobState::Processing(name) => write!(f, "PROCESSING_{}", name.to_uppercase()),
            JobState::Completed(id) => write!(f, "SUCCESS_JOB_ID_{}", id),
            JobState::Failed(reason) => write!(f, "ERROR_REASON: {}", reason.to_uppercase()),
        }
    }
}

impl JobState {
    fn transition(&self, action: &str) -> Result<JobState, String> {
        match (self, action) {
            (JobState::Pending, "START") => Ok(JobState::Processing(String::from("EMBEDDING_JOB"))),
            (JobState::Processing(_), "FINALIZE" | "SUCCESS") => {
                let new_id = rand::random::<u64>();
                Ok(JobState::Completed(new_id))
            },
            (JobState::Processing(_), "FAIL") => Ok(JobState::Failed(String::from("Invalid input data received"))),
            (JobState::Completed(_), _) => Err(format!("Cannot change state from Completed using action: {}", action)),
            (JobState::Failed(_), _) => Err(format!("Cannot retry job manually; must be reset first.")),
            _ => Err(format!("Invalid transition attempted. Current State: {}, Action: {}", self, action)),
        }
    }
}

fn main() -> io::Result<()> {
    let mut current_state = JobState::Pending;
    println!("Initial Status: {}", current_state);

    match current_state.transition(&String::from("START")) {
        Ok(next_state) => {
            current_state = next_state;
            println!("Transition 1 Successful: {}", current_state);
        }
        Err(e) => {
            eprintln!("Transition Failed on Start: {}", e);
            return Ok(());
        }
    }

    match current_state.transition(&String::from("SUCCESS")) {
        Ok(next_state) => {
            current_state = next_state;
            println!("Transition 2 Successful: {}", current_state);
        }
        Err(e) => {
            eprintln!("Transition Failed on Success: {}", e);
        }
    }

    match current_state.transition(&String::from("FINALIZE")) {
        Ok(_) => {},
        Err(e) => eprintln!("Attempted invalid transition: {}", e),
    }

    Ok(())
}

use std::time::Duration;

#[derive(Debug, PartialEq, Clone, Copy)]
enum TimerState {
    Ready,
    CountingDown,
    Paused,
}

struct PomodoroTimer {
    state: TimerState,
    elapsed_time: Duration,
    initial_duration: Duration,
}

impl PomodoroTimer {
    fn new(duration: Duration) -> Self {
        PomodoroTimer {
            state: TimerState::Ready,
            elapsed_time: duration,
            initial_duration: duration,
        }
    }

    fn transition(&mut self, next_state: TimerState) -> Result<(), &'static str> {
        match (self.state, next_state) {
            (TimerState::Ready, TimerState::CountingDown) => {
                if self.elapsed_time == Duration::ZERO {
                    self.elapsed_time = self.initial_duration;
                    self.state = next_state;
                    Ok(())
                } else {
                    Err("Cannot start countdown when time is not set.")
                }
            },
            (TimerState::CountingDown, TimerState::Paused) => {
                self.state = next_state;
                Ok(())
            },
            (TimerState::Paused, TimerState::CountingDown) => {
                self.state = next_state;
                Ok(())
            },
            (_, _) => Err("Invalid state transition attempted.")
        }
    }

    fn tick(&mut self) -> Result<(), &'static str> {
        match self.state {
            TimerState::CountingDown => {
                self.elapsed_time = self.elapsed_time.saturating_sub(Duration::from_millis(100));
                if self.elapsed_time == Duration::ZERO {
                    self.transition(TimerState::Ready).map_err(|_| "Transition failed on zero tick.")?;
                }
                Ok(())
            },
            _ => Err("Cannot tick outside of CountingDown state.")
        }
    }

    fn get_status(&self) -> (TimerState, Duration) {
        (self.state, self.elapsed_time)
    }
}

fn main() {
    let mut timer = PomodoroTimer::new(Duration::from_secs(2));
    println!("Initial status: {:?}", timer.get_status());

    if let Ok(_) = timer.transition(TimerState::CountingDown) {
        println!("Transitioned to CountingDown.");
    }

    for i in 0..3 {
        match timer.tick() {
            Ok(_) => println!("Tick {} successful: {:?}", i + 1, timer.get_status()),
            Err(e) => println!("Tick failed: {}", e),
        }
    }

    if let Ok(_) = timer.transition(TimerState::Paused) {
        println!("Transitioned to Paused.");
    }
    println!("Final status: {:?}", timer.get_status());
}
